import java.lang.reflect.Field;

import org.junit.jupiter.api.AfterEach;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

class CSVFormatTest {

    private CSVFormat csvFormat;
    private PrintStream originalOut;

    @BeforeEach
    void setUp() {
        csvFormat = CSVFormat.newFormat(',');
        // Save original System.out
        originalOut = System.out;
    }

    @AfterEach
    void tearDown() {
        // Restore original System.out
        System.setOut(originalOut);
    }

    @Test
    void testPrinterNotNull() throws IOException {
        CSVPrinter printer = csvFormat.printer();
        assertNotNull(printer);
    }

    @Test
    void testPrinterUsesSystemOut() throws IOException, NoSuchFieldException, IllegalAccessException {
        // Create a spy on an OutputStream wrapping System.out to detect usage
        OutputStream spyOut = spy(originalOut);
        PrintStream spyPrintStream = new PrintStream(spyOut);
        System.setOut(spyPrintStream);

        CSVPrinter printer = csvFormat.printer();
        assertNotNull(printer);

        // Use reflection to get the private 'out' field of CSVPrinter
        Field outField = CSVPrinter.class.getDeclaredField("out");
        outField.setAccessible(true);
        Object outObject = outField.get(printer);

        // The 'out' field is a Writer wrapping the PrintStream's underlying OutputStream,
        // so we check that the PrintStream inside CSVPrinter ultimately wraps our spyPrintStream
        // We can check that the CSVPrinter's OutputStream is the same as spyPrintStream's underlying OutputStream
        // But since 'out' is a Writer, we just check that the underlying PrintStream is spyPrintStream
        // Because CSVPrinter uses an OutputStreamWriter wrapping the PrintStream

        // Instead, verify that writing to printer writes to our spyOut by invoking print and verifying spyOut
        printer.print("test");
        verify(spyOut, atLeastOnce()).write(any(byte[].class), anyInt(), anyInt());
    }

}
